try {
  localStorage.setItem('myCache', 빽빽한_데이터);
} catch (e) {
  if (e.name === 'QuotaExceededError') {
    // 1. 오래된 캐시나 특정 키 삭제
    localStorage.removeItem('oldCache');
    // 2. 또는 전체 초기화 후 재시도
    localStorage.clear();
    localStorage.setItem('myCache', 빽빽한_데이터);
  }
}

import React, { Suspense, lazy } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';

// ❌ 기존 방식 (앱 실행 시 무조건 다 불러옴)
// import Home from './pages/Home';
// import About from './pages/About';

// ✅ Lazy 방식 (해당 라우트로 이동할 때만 파일을 불러옴)
const Home = lazy(() => import('./pages/Home'));
const About = lazy(() => import('./pages/About'));

function App() {
  return (
    <Router>
      {/* Suspense로 라우트들을 감싸줍니다. 데이터(컴포넌트)를 불러오는 동안 fallback UI가 뜹니다. */}
      <Suspense fallback={<div>페이지를 불러오는 중입니다... 🌀</div>}>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/about" element={<About />} />
        </Routes>
      </Suspense>
    </Router>
  );
}

export default App;
